let nilai = [85, 45, 90, 30, 78, 55, 92, 40];
let lulus = nilai.filter(function(n) { return n >= 60; });
console.log(lulus);
let total = nilai.reduce(function(acc, n) { return acc + n; }, 0);
console.log(total);
let rataRata = nilai.reduce(function(acc, n) { return acc + n; }, 0) / nilai.length;
console.log(rataRata);
